package org.seweb.reciperecommenderxmljava.controller;

import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class HomeController {

    @GetMapping("/")
    public String home() {
        return "index";
    }
}

package org.seweb.reciperecommenderxmljava.model;

import jakarta.validation.constraints.NotBlank;

public class AppUser {

    @NotBlank(message = "First name is required")
    private String firstName;

    @NotBlank(message = "Last name is required")
    private String lastName;

    @NotBlank(message = "Skill level is required")
    private String skillLevel;

    @NotBlank(message = "Preferred cuisine type is required")
    private String preferredCuisineType;

    public AppUser() {
    }

    public AppUser(String firstName, String lastName, String skillLevel, String preferredCuisineType) {
        this.firstName = firstName;
        this.lastName = lastName;
        this.skillLevel = skillLevel;
        this.preferredCuisineType = preferredCuisineType;
    }

    public String getFirstName() {
        return firstName;
    }

    public void setFirstName(String firstName) {
        this.firstName = firstName;
    }

    public String getLastName() {
        return lastName;
    }

    public void setLastName(String lastName) {
        this.lastName = lastName;
    }

    public String getSkillLevel() {
        return skillLevel;
    }

    public void setSkillLevel(String skillLevel) {
        this.skillLevel = skillLevel;
    }

    public String getPreferredCuisineType() {
        return preferredCuisineType;
    }

    public void setPreferredCuisineType(String preferredCuisineType) {
        this.preferredCuisineType = preferredCuisineType;
    }
}

package org.seweb.reciperecommenderxmljava.model;

import jakarta.validation.constraints.NotBlank;

public class Recipe {

    private int id;

    @NotBlank(message = "Title is required")
    private String title;

    @NotBlank(message = "First cuisine type is required")
    private String cuisineType1;

    @NotBlank(message = "Second cuisine type is required")
    private String cuisineType2;

    @NotBlank(message = "Difficulty is required")
    private String difficulty;

    public Recipe() {
    }

    public Recipe(int id, String title, String cuisineType1, String cuisineType2, String difficulty) {
        this.id = id;
        this.title = title;
        this.cuisineType1 = cuisineType1;
        this.cuisineType2 = cuisineType2;
        this.difficulty = difficulty;
    }

    public int getId() {
        return id;
    }

    public void setId(int id) {
        this.id = id;
    }

    public String getTitle() {
        return title;
    }

    public void setTitle(String title) {
        this.title = title;
    }

    public String getCuisineType1() {
        return cuisineType1;
    }

    public void setCuisineType1(String cuisineType1) {
        this.cuisineType1 = cuisineType1;
    }

    public String getCuisineType2() {
        return cuisineType2;
    }

    public void setCuisineType2(String cuisineType2) {
        this.cuisineType2 = cuisineType2;
    }

    public String getDifficulty() {
        return difficulty;
    }

    public void setDifficulty(String difficulty) {
        this.difficulty = difficulty;
    }
}

* {
    box-sizing: border-box;
}

body {
    margin: 0;
    font-family: Arial, Helvetica, sans-serif;
    background: linear-gradient(135deg, #f5f7fb, #e8eef8);
    color: #1f2937;
}

.page-container {
    min-height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 24px;
}

.card {
    width: 100%;
    max-width: 720px;
    background: #ffffff;
    border-radius: 18px;
    padding: 40px;
    box-shadow: 0 12px 30px rgba(15, 23, 42, 0.08);
    border: 1px solid #e5e7eb;
}

.badge {
    display: inline-block;
    margin: 0 0 16px;
    padding: 6px 12px;
    border-radius: 999px;
    background: #dbeafe;
    color: #1d4ed8;
    font-size: 0.85rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.04em;
}

h1 {
    margin: 0 0 12px;
    font-size: 2.1rem;
}

.subtitle {
    margin: 0 0 24px;
    font-size: 1rem;
    color: #4b5563;
}

.status-box {
    padding: 20px;
    border-radius: 14px;
    background: #f9fafb;
    border: 1px solid #e5e7eb;
}

.status-box h2 {
    margin-top: 0;
    margin-bottom: 8px;
    font-size: 1.1rem;
}

.status-box p {
    margin: 0;
    line-height: 1.6;
}
